      'Patch this TypeScript file and run the local build',
      [PRIMARY_PROVIDER_ID, HAIKU_PROVIDER_ID],
      { kind: 'research' },
      capabilities,
    )).toBe(HAIKU_PROVIDER_ID);
  });
});
